"use client";

import { m } from "framer-motion";

import {
  Briefcase,
    Globe,
      Cpu,
        GraduationCap,
          Heart,
            ShieldCheck,
              Circle,
              } from "lucide-react";

              import { milestones, Milestone } from "@/data/timeline";

              import { cn } from "@/lib/utils";

              const getIcon = (type: Milestone["type"]) => {
                switch (type) {
                    case "GOVERNANCE":
                          return <ShieldCheck size={16} />;

                              case "INDUSTRIAL":
                                    return <Cpu size={16} />;

                                        case "INTERNATIONAL":
                                              return <Globe size={16} />;

                                                  case "HUMANITARIAN":
                                                        return <Heart size={16} />;

                                                            case "TECHNICAL":
                                                                  return <Briefcase size={16} />;

                                                                      case "EDUCATION":
                                                                            return <GraduationCap size={16} />;

                                                                                default:
                                                                                      return <Circle size={16} />;
                                                                                        }
                                                                                        };

                                                                                        export default function Timeline() {
                                                                                          return (
                                                                                              <section
                                                                                                    id="timeline"
                                                                                                          className="relative py-24 px-6 bg-background overflow-hidden"
                                                                                                              >
                                                                                                                    <div className="max-w-4xl mx-auto relative">
                                                                                                                            {/* Header */}
                                                                                                                                    <div className="mb-20 space-y-4">
                                                                                                                                              <div className="flex items-center gap-3 text-emerald-primary font-mono text-xs uppercase tracking-[0.3em]">
                                                                                                                                                          <div className="h-px w-8 bg-emerald-primary/40" />

                                                                                                                                                                      Mission Log
                                                                                                                                                                                </div>

                                                                                                                                                                                          <h2 className="text-3xl md:text-5xl font-bold tracking-tight">
                                                                                                                                                                                                      Professional <br />

                                                                                                                                                                                                                  <span className="text-gray-500">
                                                                                                                                                                                                                                Chronology
                                                                                                                                                                                                                                            </span>
                                                                                                                                                                                                                                                      </h2>

                                                                                                                                                                                                                                                                <p className="text-gray-400 font-mono text-xs md:text-sm max-w-md leading-relaxed">
                                                                                                                                                                                                                                                                            Technical deployments, international
                                                                                                                                                                                                                                                                                        coordination, and industrial systems
                                                                                                                                                                                                                                                                                                    management.
                                                                                                                                                                                                                                                                                                              </p>
                                                                                                                                                                                                                                                                                                                      </div>

                                                                                                                                                                                                                                                                                                                              {/* Line */}
                                                                                                                                                                                                                                                                                                                                      <div className="absolute left-4 md:left-1/2 top-64 bottom-0 w-px bg-gradient-to-b from-emerald-primary/50 via-white/5 to-transparent -translate-x-1/2 hidden md:block" />

                                                                                                                                                                                                                                                                                                                                              {/* Timeline */}
                                                                                                                                                                                                                                                                                                                                                      <div className="space-y-12 md:space-y-0 relative">
                                                                                                                                                                                                                                                                                                                                                                {milestones.map((item, idx) => (
                                                                                                                                                                                                                                                                                                                                                                            <m.div
                                                                                                                                                                                                                                                                                                                                                                                          key={`${item.year}-${idx}`}
                                                                                                                                                                                                                                                                                                                                                                                                        initial={{ opacity: 0, y: 30 }}
                                                                                                                                                                                                                                                                                                                                                                                                                      whileInView={{ opacity: 1, y: 0 }}
                                                                                                                                                                                                                                                                                                                                                                                                                                    viewport={{ once: true }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                  transition={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  duration: 0.5,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  delay: idx * 0.1,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              className={cn(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              "relative flex flex-col md:flex-row items-start md:items-center gap-8 md:gap-0",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              idx % 2 === 0
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ? "md:flex-row-reverse"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  : ""
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {/* Card */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="w-full md:w-[45%] group">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="relative p-6 rounded-xl border border-white/5 bg-panel/50 backdrop-blur-sm transition-all duration-500 group-hover:border-emerald-primary/30 group-hover:bg-panel">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="flex justify-between items-start mb-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <span className="text-xs font-mono text-emerald-primary/80 tracking-tighter">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {item.type}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </span>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <span
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  className={cn(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          "px-2 py-0.5 rounded text-[9px] font-mono border uppercase tracking-widest",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  item.status === "CURRENT"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ? "text-emerald-primary border-emerald-primary/20 bg-emerald-soft"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      : "text-gray-500 border-white/5"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {item.status}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <h3 className="text-lg font-semibold text-white group-hover:text-emerald-primary transition-colors">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {item.title}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </h3>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <p className="text-sm text-gray-400 mt-1">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {item.org}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </p>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="mt-4 pt-4 border-t border-white/5 flex items-center justify-between">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <span className="text-[10px] font-mono text-gray-500 uppercase">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {item.loc}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </span>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <span className="text-[10px] font-mono text-emerald-primary md:hidden">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {item.year}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {/* Node */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="absolute left-4 md:left-1/2 top-0 md:top-auto -translate-x-1/2 flex items-center justify-center z-20">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="w-8 h-8 rounded-full bg-background border border-emerald-primary/40 flex items-center justify-center text-emerald-primary shadow-[0_0_15px_rgba(16,185,129,0.2)]">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {getIcon(item.type)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {/* Year */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  className={cn(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    "hidden md:block w-[45%] text-2xl font-bold font-mono tracking-tighter",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      idx % 2 === 0
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          ? "text-right pr-12"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              : "text-left pl-12",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                item.status === "CURRENT"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ? "text-emerald-primary"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        : "text-gray-700"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {item.year}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </m.div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </section>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }